parser <- ArgumentParser()
parser$add_argument("-i", "--input", action="store",
                    help="path to input count file: count number of fragments falling into each bin")
parser$add_argument("-b", "--bin", action="store",
                    help="path to input bam fiel")
parser$add_argument("-o", "--output", action="store",
                    help="Path to save  output")

args <- parser$parse_args()

path.to.count.file <- args$input
outputdir <- args$output
path.to.binfile <- args$bin

bin.name <- str_replace_all(basename(path.to.binfile), ".rds", "")

message(sprintf("Input input file %s", basename(path.to.count.file)))
message(sprintf("output will be saved to %s", outputdir))
message(sprintf("Using the CNA bin file %s, name %s", path.to.binfile, bin.name))

binfile <- readRDS(path.to.binfile)

