#             sep = "\t", quote = FALSE, row.names = FALSE, col.names = FALSE)

generate_QDNAseq_readCountObj <- function(path.to.count.file, binfile){
  sample.name <- basename(path.to.count.file)
  countdf <- read.csv(path.to.count.file, sep = "\t", header = FALSE)
  colnames(countdf) <- c("chromosome", "start", "end", "count")
  countdf <- countdf %>% rowwise() %>%
    mutate(bin = sprintf("%s:%s-%s", chromosome, start, end)) %>%
    column_to_rownames("bin") %>% subset(select = -c(start, end, chromosome))
  colnames(countdf) <- c(sample.name)
  
  fd <- new("AnnotatedDataFrame", data = countdf)
  pd <- new("AnnotatedDataFrame", data = data.frame(
    name = sample.name,
    total.reads = sum(countdf$count),
    used.reads = sum(countdf$count),
    expected.variance = nrow(binfile@data)/sum(countdf$count)
  ))
  row.names(pd) <- sample.name
  readCounts <- new("QDNAseqReadCounts",
                    counts = as.matrix(countdf),
                    rowRanges = binfile,
                    phenodata = pd,
                    featuredata = fd,
                    bins = binfile)
  return(readCounts)
}

calculate_CNA <- function(readCounts){
  readCountsFiltered <- applyFilters(readCounts, residual=TRUE, blacklist=TRUE)
  readCountsFiltered <- estimateCorrection(readCountsFiltered)
  copyNumbers <- correctBins(readCountsFiltered)
  copyNumbersNormalized <- normalizeBins(copyNumbers)
  copyNumbersSmooth <- smoothOutlierBins(copyNumbersNormalized)
  
  copyNumbersSegmented <- segmentBins(copyNumbersSmooth, transformFun="log2")
  copyNumbersSegmented <- normalizeSegmentedBins(copyNumbersSegmented)
  
  copyNumbersCalled <- callBins(copyNumbersSegmented)
  function.output <- list(CNA = copyNumbersCalled, readCounts = readCountsFiltered)
  return(function.output)  
}

format_cna_output <- function(cna.obj){
  # ***** save copy number data frame
  # and format the dataframe as <chr>TAB<start>TAB<end>TAB<Log2-ratio>
  cnadf <- data.frame(cna.obj$CNA@assayData$copynumber) %>%
    rownames_to_column("bin.name")
  colnames(cnadf) <- c("bin.name", "log2.ratio")
  cnadf <- cnadf %>% rowwise() %>%
    mutate(chrom = sprintf("chr%s", str_split(bin.name, ":")[[1]][[1]])) %>%
    mutate(start = str_split(str_split(bin.name, ":")[[1]][[2]], "-")[[1]][[1]] ) %>%
    mutate(end = str_split(str_split(bin.name, ":")[[1]][[2]], "-")[[1]][[2]] )
  
  cnadf <- cnadf[, c("chrom", "start", "end", "log2.ratio")]
  return(cnadf)
}

readCounts <- generate_QDNAseq_readCountObj(path.to.count.file, binfile)
cna.bin <- calculate_CNA(readCounts)
output.cnadf <- format_cna_output(cna.bin)

write.table(output.cnadf, 
            file.path(outputdir, sprintf("%s.%s.bed", filename, bin.name)), 
            sep = "\t", 
            row.names = FALSE, 
            col.names = FALSE)

